import axios, { AxiosInstance } from 'axios';

export class SmithersRuntimeClient {
  private client: AxiosInstance;

  constructor(baseUrl: string, apiKey: string) {
    this.client = axios.create({
      baseURL: baseUrl,
      headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' }
    });
  }

  async provision(image: string): Promise<{ sandboxId: string }> {
    const { data } = await this.client.post('/v1/sandboxes', { image });
    return data;
  }

  async runCommand(sandboxId: string, command: string): Promise<void> {
    // This triggers the remote execution
    await this.client.post(`/v1/sandboxes/${sandboxId}/exec`, { command });
  }

  async getLogs(sandboxId: string): Promise<{ stdout: string; stderr: string; exitCode: number }> {
    const { data } = await this.client.get(`/v1/sandboxes/${sandboxId}/logs`);
    return data;
  }

  async destroy(sandboxId: string): Promise<void> {
    await this.client.delete(`/v1/sandboxes/${sandboxId}`);
  }
}
